PyTypeObject* DoInitWrapperLinearColor(const UScriptStruct* InStruct, PyTypeObject* InSuperType)
{
	if (InStruct == nullptr)
	{
		return nullptr;
	}

	if (FUPyWrapperTypeRegistry::Get().HasWrappedStructType(InStruct))
	{
		return const_cast<PyTypeObject*>(FUPyWrapperTypeRegistry::Get().GetWrappedStructType(InStruct));
	}

	PyTypeObject* PyType = &UPyWrapperLinearColorType;
	PyType->tp_flags = Py_TPFLAGS_DEFAULT | Py_TPFLAGS_BASETYPE;
	PyType->tp_base = InSuperType != nullptr ? InSuperType : &UPyWrapperStructType;
	PyType->tp_init = (initproc)&FFuncs_LinearColor::Init;
	PyType->tp_methods = FUPyWrapperLinearColorPyMethodDefs;
	PyType->tp_getset = FUPyWrapperLinearColorGetSets;
	PyType->tp_richcompare = (richcmpfunc)&FFuncs_LinearColor::RichCmp;
	static PyNumberMethods PyNumber;
	PyNumber.nb_add = (binaryfunc)&FNumberFuncs_LinearColor::Op_add;
	PyNumber.nb_inplace_add = (binaryfunc)&FNumberFuncs_LinearColor::Op_iadd;
	PyNumber.nb_inplace_multiply = (binaryfunc)&FNumberFuncs_LinearColor::Op_imul;
	PyNumber.nb_inplace_subtract = (binaryfunc)&FNumberFuncs_LinearColor::Op_isub;
	PyNumber.nb_multiply = (binaryfunc)&FNumberFuncs_LinearColor::Op_mul;
	PyNumber.nb_subtract = (binaryfunc)&FNumberFuncs_LinearColor::Op_sub;
	PyNumber.nb_true_divide = (binaryfunc)&FNumberFuncs_LinearColor::Op_truediv;
	PyType->tp_as_number = &PyNumber;

	if (PyType_Ready(PyType) == 0)
	{
		FUPyConstantDef::AddConstantsToType(FConstants_LinearColor::Table(), PyType);
		FUPyWrapperTypeRegistry::Get().RegisterWrappedStructType(InStruct, PyType);
		return PyType;
	}

	return nullptr;

}

void InitializeUPyWrapperLinearColor(UPyGenUtil::FNativePythonModule& ModuleInfo)
{
	FUPyWrapperTypeRegistry::Get().RegisterInlineStructFactory(StaticCastSharedRef<const IUPyWrapperInlineStructFactory>(MakeShared<TUPyWrapperInlineStructFactory<FLinearColor>>()));
	FUPyWrapperTypeRegistry::Get().RegisterAutoWrappedStructCreateFunc(TBaseStructure<FLinearColor>::Get(), DoInitWrapperLinearColor);
}

PyObject* FUPyWrapperLinearColor::CreateInstance(const FLinearColor& InValue, const FUPyWrapperOwnerContext& InOwnerContext, const EUPyConversionMethod InConversionMethod)
{
	return (PyObject*)FUPyWrapperStructFactory::Get().CreateInstance(&UPyWrapperLinearColorType, TBaseStructure<FLinearColor>::Get(), (void*)&InValue, InOwnerContext, InConversionMethod);
}

FUPyWrapperLinearColor* UPyIsLinearColor(PyObject* InSelf)
{
	if (InSelf && PyObject_TypeCheck(InSelf, &UPyWrapperLinearColorType))
	{
		return (FUPyWrapperLinearColor*)InSelf;
	}
	return nullptr;
}

namespace UPyConversion
{
	FUPyConversionResult NativizeStructInstance(PyObject* PyObj, FLinearColor& OutVal, const ESetErrorState SetErrorState)
	{
		if (FUPyWrapperLinearColor* PyVector = UPyIsLinearColor(PyObj))
		{
			OutVal = *PyVector->ValuePtr();
			return FUPyConversionResult::Success();
		}

		UPYCONVERSION_RETURN(FUPyConversionResult::Failure(), TEXT("NativizeStructInstance"), *FString::Printf(TEXT("Cannot nativize '%s' as 'FLinearColor'"), *UPyUtil::GetFriendlyTypename(PyObj)));
	}
	
	FUPyConversionResult PythonizeStructInstance(const FLinearColor& InVal, PyObject*& OutPyObj, const ESetErrorState SetErrorState)
	{
		OutPyObj = FUPyWrapperLinearColor::CreateInstance(InVal, FUPyWrapperOwnerContext(), EUPyConversionMethod::Copy);
		return FUPyConversionResult::Success();
	}
}
